// script.js
import Paper from 'paper.js';
Paper.init();
const paper = new Paper('my-svg');
const points = [];
paper.view.draw = function () {
    if (points.length < 50) {
        points.push({x: Math.random() * 400, y: Math.random() * 400});
        const paths = points.map((point, i) => {
            return `M ${point.x} ${point.y}`;
        }).join('\n');
        paper.project.activeLayer.item(0).setAttribute('d', paths);
    } else {
        paper.project.activeLayer.clear();
        points = [];
    }
}
// Update the path every 20ms
setInterval(paper.view.draw, 20)
